input.command:
PW=$(kubectl -n mongodb get secret admin-user-password -o jsonpath="{.data.password}" 2>/dev/null | base64 -d)
AU="-u admin-user -p $PW --authenticationDatabase admin"
# write a probe to primary with w:3 majority, then read from a secondary
kubectl -n mongodb exec mongodb-replica-0 -- mongosh --quiet $AU --eval '
db.getSiblingDB("app").health_probe.insertOne({t:new Date()},{writeConcern:{w:3,wtimeout:15000}});
print("w3 write OK");
var st=rs.status();
st.members.forEach(m=>print(m.name.split(".")[0]+" "+m.stateStr+" lagSecs="+ (m.optimeDate? (st.date-m.optimeDate)/1000 : "?")));
' 2>&1 | grep -v Defaulted
echo "--- read from secondary ---"
kubectl -n mongodb exec mongodb-replica-1 -- mongosh --quiet $AU --eval 'rs.secondaryOk?rs.secondaryOk():null; db.getMongo().setReadPref("secondary"); print("probe count on sec="+db.getSiblingDB("app").health_probe.countDocuments({}));' 2>&1 | grep -v Defaulted
